function Sidebar({ chats, activeChatId, onNewChat, onSelectChat }) {
    return (
        <div
            style={{
                width: "260px",
                backgroundColor: "#111827",
                color: "white",
                display: "flex",
                flexDirection: "column",
            }}
        >
            <button
                onClick={onNewChat}
                style={{
                    margin: "12px",
                    padding: "10px",
                    borderRadius: "8px",
                    backgroundColor: "#2563eb",
                    color: "white",
                    border: "none",
                    cursor: "pointer",
                }}
            >
                ➕ New Chat
            </button>

            <div style={{ flex: 1, overflowY: "auto" }}>
                {chats.map((chat) => (
                    <div
                        key={chat.id}
                        onClick={() => onSelectChat(chat.id)}
                        style={{
                            padding: "10px 12px",
                            cursor: "pointer",
                            backgroundColor:
                                chat.id === activeChatId ? "#1f2937" : "transparent",
                        }}
                    >
                        {chat.title || "New Conversation"}
                    </div>
                ))}
            </div>
        </div>
    );
}

export default Sidebar;
